def solve(s: str) -> bool:
    stack = []
    quote = None
    i = 0
    while i < len(s):
        c = s[i]
        if c == '\\':
            i += 2
            continue
        if quote:
            if c == quote:
                quote = None
        else:
            if c in '\'"':
                quote = c
            elif c in '([{':
                stack.append(c)
            elif c in ')]}':
                if not stack:
                    return False
                top = stack.pop()
                if (c == ')' and top != '(') or \
                   (c == ']' and top != '[') or \
                   (c == '}' and top != '{'):
                    return False
        i += 1
    return not stack
```

