def solve(pattern: str, text: str) -> bool:
    i, j = 0, 0
    star_j, match_i = -1, 0

    while i < len(text):
        if j < len(pattern) and (pattern[j] == '?' or pattern[j] == text[i]):
            i += 1
            j += 1
        elif j < len(pattern) and pattern[j] == '*':
            star_j = j
            match_i = i
            j += 1
        elif star_j != -1:
            j = star_j + 1
            match_i += 1
            i = match_i
        else:
            return False

    while j < len(pattern) and pattern[j] == '*':
        j += 1

    return j == len(pattern)
